import org.apache.commons.lang3.StringEscapeUtils;

public class XSSFixedCode {
    public static void main(String[] args) {
        // Simulating user input coming from a form submission
        String userInput = "<script>alert('XSS Vulnerability!')</script>";

        // Escaping user input to prevent XSS attacks
        String escapedInput = StringEscapeUtils.escapeHtml4(userInput);

        // Output the properly escaped input to an HTML page
        System.out.println("<div>" + escapedInput + "</div>");
    }
}

